cy.visit(`${webAppBaseURL}/schedule/scores`);
cy.wait(5000);
const today = new Date();
const todayString = today.toISOString().split("T")[0];
cy.get(".mls-c-schedule__matches").then(schedule => {
  if (schedule.find('div[class*="mls-c-match-tile --post"]').length > 0) {
    cy.get('div[class*="mls-c-match-tile --post"]').each($div => {
      const postMatchLink = $div.parent("a").prop("href");
      if (postMatchLink) {
        const matchInfo = getTeamsAndDateFromURL(postMatchLink);
        if (matchInfo && matchInfo.MatchDate === todayString) {
          postMatchURLs.push(postMatchLink);
        }
      }
    });
  } else {
    cy.log('No elements with class containing "mls-c-match-tile --post" found.');
  }
  const postMatchObj = {
    postMatchURLs
  };
  cy.writeFile("MLS_SMOKE_TEST_URLS.json", postMatchObj);
  cy.log(`postMatchURLs array written to: MLS_SMOKE_TEST_URLS.json`);
});
cy.get(".mls-c-schedule__matches").then(schedule => {
  if (schedule.find('div[class*="mls-c-match-tile --pre"]').length > 0) {
    cy.get('div[class*="mls-c-match-tile --pre"]').each($div => {
      const preMatchLink = $div.parent("a").prop("href");
      if (preMatchLink) {
        const matchInfo = getTeamsAndDateFromURL(preMatchLink);
        if (matchInfo && matchInfo.MatchDate === todayString) {
          preMatchURLs.push(preMatchLink);
        }
      }
    });
  } else {
    cy.log('No elements with class containing "mls-c-match-tile --pre" found.');
  }
  const tempUrlsObj = {
    postMatchURLs,
    preMatchURLs
  };
  cy.writeFile("MLS_SMOKE_TEST_URLS.json", tempUrlsObj);
  cy.log(`preMatchURLs array written to: MLS_SMOKE_TEST_URLS.json`);
});
